import React from 'react'
import {ChatEngine} from 'react-chat-engine'

const ChatBox = () => {
  return (
    <div>

<ChatEngine offset={-4}
      height='100vh'
      userName='MoonMoon'
      projectID = {process.env.REACT_APP_CHAT_APP_PROJECT_ID}
      userSecret={process.env.REACT_APP_CHAT_APP_USER_SECRET}

    />

    </div>
  )
}

export default ChatBox

